#include<bits/stdc++.h>
using namespace std;
long long a,b,c;
long long m[21][21][21];
long long  w(long long  a,long long  b,long long  c){
	long long  ans;

	if(a<=0||b<=0||c<=0) return ans=1;
	if(a>20||b>20||c>20) return w(20,20,20);
	if(m[a][b][c]!=-1) return m[a][b][c];
	if(a<b&&b<c) ans=w(a,b,c-1)+w(a,b-1,c-1)-w(a,b-1,c);
	else ans=w(a-1,b,c)+w(a-1,b-1,c)+w(a-1,b,c-1)-w(a-1,b-1,c-1);
	m[a][b][c]=ans;
	return ans;
}
int  main(){
	memset(m,-1,sizeof(m));
	while(1){
		cin>>a>>b>>c;
		if(a==-1&&b==-1&&c==-1) return 0;
		else cout<<"w("<<a<<", "<<b<<", "<<c<<") = "<<w(a,b,c)<<'\n';
	}

	return 0;
}
